import{_ as e,p as a,q as i,a1 as l}from"./framework-822ca1a4.js";const h={},s=l('<h1 id="现在完成时态" tabindex="-1"><a class="header-anchor" href="#现在完成时态" aria-hidden="true">#</a> 现在完成时态</h1><h2 id="用法" tabindex="-1"><a class="header-anchor" href="#用法" aria-hidden="true">#</a> 用法</h2><ol><li>表示一个动作或者状态从过去延续到现在。谓语动词必须是延续性的，一般需要有用延续性的时间状语。</li><li>表示移动动作发生在过去，但是对现在华友影响或对现在产生了某种结果。一般用非延续性动词，不能用于主系表句型中。</li></ol><p>主谓宾构成方式：have/has + 实义动词过去分词。一般分为以下四种情况:</p><ol><li>人称代词主格 + have/has + 不及物动词过去分词</li><li>名词 + have/has + 不及物动词过去分词</li><li>人称代词主格 + have/has + 及物动词过去分词 + 宾语</li><li>名词 + have/has + 及物动词过去分词 + 宾语</li></ol><p>变一般疑问句，have/has 移动到句首，过去分词不变。</p><p>变否定句，have/has 后面加 not。</p><p>主系表构成方式：have/has + been + 表语。一般分为以下四种情况:</p><ol><li>人称代词主格 + have/has + been + 表语（形容词）</li><li>名词 + have/has + been + 表语（形容词）</li><li>人称代词主格 + have/has + been + 表语（名词）</li><li>名词 + have/has + been + 表语（名词）</li></ol><p>变一般疑问句，have/has 移动到句首，过去分词 been 不变。</p><p>变否定句，have/has 后面加 not，过去分词 been 不变。</p><p>注意：一般过去时态和现在完成时区别。</p><p>一般过去时态是用来客观记录过去在某个时间的动作或者状态，强调过去发生了什么。现在完成时态用法二和时间没关系，只是强调现在的情况，也就是过去的动作对现在的影响。</p><h2 id="例句" tabindex="-1"><a class="header-anchor" href="#例句" aria-hidden="true">#</a> 例句</h2><p>have/has + 实义动词过去分词</p><ul><li>I have worked.</li><li>He has sat.</li><li>We have bathed.</li><li>Nick has cried.</li><li>Nick and Jack have cried.</li><li>I have seen you.</li><li>You have drunk water.</li><li>She has baked potatoes.</li><li>My leader has drunk beer.</li><li>Jack has baked a banana.</li><li>I have not worked here.</li><li>Have you backed a banana?</li><li>Jack hasn&#39;t baked a banana.</li></ul><p>have/has + been + 表语</p><ul><li>I have been busy.</li><li>He has been clever.</li><li>We have been healthy.</li><li>His sister has been kind.</li><li>Tom and Jack have been tired.</li><li>Their workers have been healthy.</li><li>I have been a teacher.</li><li>They have been drivers.</li><li>She has been a nanny.</li><li>It has been my office.</li><li>My leader has been her fan.</li><li>My fans have been bosses.</li><li>The girl has been a secretary.</li><li>His classmates have been coaches.</li><li>Have you been busy?</li><li>The man has been a doctor.</li></ul>',18),n=[s];function r(t,o){return a(),i("div",null,n)}const b=e(h,[["render",r],["__file","present-tense-3.html.vue"]]);export{b as default};
